// Optimal posting windows per platform (UTC)
const schedule = {
  instagram: { windows: [[11,13], [19,21]], days: [1,2,3,4,5] },
  tiktok: { windows: [[7,9], [12,13], [19,21]], days: [0,1,2,3,4,5,6] },
  linkedin: { windows: [[8,10], [12,14]], days: [1,2,3,4] },
  twitter: { windows: [[8,10], [12,13], [17,18]], days: [1,2,3,4,5] },
  youtube: { windows: [[12,15], [17,21]], days: [4,5,6,0] }
};

const now = new Date();
const hour = now.getUTCHours();
const day = now.getUTCDay();

const readyPlatforms = Object.entries(schedule)
  .filter(([_, cfg]) => cfg.days.includes(day))
  .filter(([_, cfg]) => cfg.windows.some(([start, end]) => hour >= start && hour < end))
  .map(([platform]) => platform);

return [{ json: { readyPlatforms, hour, day, timestamp: now.toISOString() } }];

const ready = $('Check Optimal Windows').first().json.readyPlatforms;
const posts = $('Fetch Queued Posts').all();

const toPublish = posts.filter(p => 
  ready.includes(p.json.platform) && p.json.status === 'queued'
).slice(0, 3);

return toPublish.map(p => ({ json: { ...p.json, action: 'publish' } }));
